const customers = $input.all().map(i => i.json);
const now = new Date();

return customers.map(c => {
  const daysSinceJob = c.last_job_date ? Math.floor((now - new Date(c.last_job_date)) / 86400000) : 999;

  // Recency score (0-30): <30d=30, <60d=20, <90d=10, <180d=5, else=0
  let recency = daysSinceJob < 30 ? 30 : daysSinceJob < 60 ? 20 : daysSinceJob < 90 ? 10 : daysSinceJob < 180 ? 5 : 0;

  // Frequency score (0-30): based on job_count
  let frequency = Math.min(30, (c.job_count || 0) * 3);

  // Monetary score (0-25): based on total_spend
  let monetary = Math.min(25, Math.floor((c.total_spend || 0) / 100));

  // Advocacy score (0-15): referrals + reviews
  let advocacy = Math.min(15, ((c.referrals_count || 0) * 5) + ((c.reviews_count || 0) * 3));

  const health_score = recency + frequency + monetary + advocacy;

  // Classify health
  let health_segment = health_score >= 75 ? 'champion' : health_score >= 50 ? 'loyal' : health_score >= 25 ? 'at_risk' : 'dormant';

  return { json: { id: c.id, health_score, health_segment, recency_days: daysSinceJob, needs_winback: health_score < 25 && daysSinceJob < 365 } };
});
